int main()
{
	int i,n,d=1;
	char str[101],temp;
	scanf("%d",&n);
	scanf("%s",str);
	while(d<=n)
	{
		if(n%d==0)
		{
			for(i=0;i<=(d-1)/2;i++)
			{
				temp = str[i];
				str[i] = str[d-1-i];
				str[d-1-i] = temp;
			}
		}
		d++;
	}
	printf("%s",str);
}

